// CategoryCard.jsx
import React from 'react';
import '../CategoryCard.css';

const CategoryCard = ({ icon, label, count, onClick }) => {
    return (
        <div className="knowledge-cat-card" onClick={onClick}>
            <div className="cat-icon">{icon}</div>
            <div className="cat-content">
                <span className="cat-label">{label}</span>
                <span className="cat-count">{count} articles</span>
            </div>
            <svg className="cat-arrow" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <path d="M5 12h14M12 5l7 7-7 7" />
            </svg>
        </div>
    );
};

export default CategoryCard;